Create `apps/server/src/middleware/__tests__/mcp-enabled.test.ts` with tests for the new `requireMcpEnabled` middleware.

## Implementation

Create `apps/server/src/middleware/__tests__/mcp-enabled.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { Request, Response, NextFunction } from 'express';

// Mock config-manager before importing the middleware
vi.mock('../../services/core/config-manager.js', () => ({
  configManager: {
    get: vi.fn(),
  },
}));

import { requireMcpEnabled } from '../mcp-enabled.js';
import { configManager } from '../../services/core/config-manager.js';

function createMockReq(): Partial<Request> {
  return {};
}

function createMockRes(): Partial<Response> & { statusCode?: number; body?: unknown } {
  const res: Partial<Response> & { statusCode?: number; body?: unknown } = {};
  res.status = vi.fn().mockImplementation((code: number) => {
    res.statusCode = code;
    return res;
  }) as unknown as Response['status'];
  res.json = vi.fn().mockImplementation((data: unknown) => {
    res.body = data;
    return res;
  }) as unknown as Response['json'];
  return res;
}

describe('requireMcpEnabled', () => {
  let next: NextFunction;

  beforeEach(() => {
    next = vi.fn();
    vi.mocked(configManager.get).mockReturnValue(undefined);
  });

  it('calls next() when mcp.enabled is true', () => {
    vi.mocked(configManager.get).mockReturnValue({ enabled: true, apiKey: null, rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 } });
    const req = createMockReq();
    const res = createMockRes();
    requireMcpEnabled(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('calls next() when mcp config is undefined (default enabled)', () => {
    vi.mocked(configManager.get).mockReturnValue(undefined);
    const req = createMockReq();
    const res = createMockRes();
    requireMcpEnabled(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('returns 503 with JSON-RPC error when mcp.enabled is false', () => {
    vi.mocked(configManager.get).mockReturnValue({ enabled: false, apiKey: null, rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 } });
    const req = createMockReq();
    const res = createMockRes();
    requireMcpEnabled(req as Request, res as Response, next);
    expect(next).not.toHaveBeenCalled();
    expect(res.statusCode).toBe(503);
    expect(res.body).toEqual({
      jsonrpc: '2.0',
      error: { code: -32000, message: 'External MCP access is disabled.' },
      id: null,
    });
  });
});
```

Follows the exact same test pattern as the existing `mcp-auth.test.ts` — mock the dependency module, import the middleware, use `createMockReq`/`createMockRes`/`next` helpers.

## Acceptance Criteria

- All three test cases pass: enabled, undefined config (default), disabled
- Tests follow the existing `mcp-auth.test.ts` pattern for consistency
- `pnpm vitest run apps/server/src/middleware/__tests__/mcp-enabled.test.ts` passes

Extend `apps/server/src/middleware/__tests__/mcp-auth.test.ts` with additional test cases covering the new config-key fallback behavior.

## Implementation

