### 3. Add new test cases (after the existing tests):

```typescript
describe('config key fallback', () => {
  it('reads API key from config when env var is unset', () => {
    vi.mocked(configManager.get).mockReturnValue({
      enabled: true,
      apiKey: 'dork_config_secret_key',
      rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 },
    });
    const req = createMockReq('Bearer dork_config_secret_key');
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('env var overrides config key', () => {
    (env as { MCP_API_KEY: string | undefined }).MCP_API_KEY = 'env-key';
    vi.mocked(configManager.get).mockReturnValue({
      enabled: true,
      apiKey: 'config-key',
      rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 },
    });
    // Token matches env, not config
    const req = createMockReq('Bearer env-key');
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });

  it('rejects invalid Bearer token against config key', () => {
    vi.mocked(configManager.get).mockReturnValue({
      enabled: true,
      apiKey: 'dork_config_secret_key',
      rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 },
    });
    const req = createMockReq('Bearer wrong-key');
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).not.toHaveBeenCalled();
    expect(res.statusCode).toBe(401);
  });

  it('passes when no auth configured (config null + env unset)', () => {
    vi.mocked(configManager.get).mockReturnValue({
      enabled: true,
      apiKey: null,
      rateLimit: { enabled: true, maxPerWindow: 60, windowSecs: 60 },
    });
    const req = createMockReq();
    const res = createMockRes();
    mcpApiKeyAuth(req as Request, res as Response, next);
    expect(next).toHaveBeenCalled();
  });
});
```

## Acceptance Criteria

- All existing tests continue to pass (the existing mock for `env.MCP_API_KEY` still works, and the new `configManager.get` mock returns `undefined` by default which matches the old behavior)
- New test: validates against config key when env var is unset
- New test: env var takes precedence over config key
- New test: rejects invalid token against config key
- New test: passes through when both config and env are unset/null
- `pnpm vitest run apps/server/src/middleware/__tests__/mcp-auth.test.ts` passes

Extend `apps/server/src/routes/__tests__/config.test.ts` with test cases for the new MCP config GET response section and the new POST/DELETE endpoints.

## Implementation

Add new test blocks to the existing config route test file. The file already has the test infrastructure (temp dir, config manager init, express app setup) — add new describe blocks.

### 1. Add describe block for GET response MCP section:

```typescript
describe('GET /api/config — mcp section', () => {
  let app: express.Express;
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = createTempDir();
    process.env.DORK_HOME = tmpDir;

    const { initConfigManager } = await import('../../services/core/config-manager.js');
    initConfigManager(tmpDir);

    const configRouter = (await import('../config.js')).default;
    app = express();
    app.use(express.json());
    app.use('/api/config', configRouter);
  });

  afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
    vi.resetModules();
  });

  it('returns mcp section with defaults when no key configured', async () => {
    const response = await request(app).get('/api/config').expect(200);
    expect(response.body.mcp).toBeDefined();
    expect(response.body.mcp.enabled).toBe(true);
    expect(response.body.mcp.authConfigured).toBe(false);
    expect(response.body.mcp.authSource).toBe('none');
    expect(response.body.mcp.endpoint).toMatch(/http:\/\/localhost:\d+\/mcp/);
    expect(response.body.mcp.rateLimit).toEqual({
      enabled: true,
      maxPerWindow: 60,
      windowSecs: 60,
    });
  });
});
```

### 2. Add describe block for POST /mcp/generate-key:

```typescript
